function hash(data:Buffer|string){return crypto.createHash('sha256').update(data).digest('hex');}
function decode(data:string){return zlib.gunzipSync(Buffer.from(data,'base64'));}
function findRoot(start=process.cwd()){
  let current=path.resolve(start);
  for(let i=0;i<10;i++){
    if(fs.existsSync(path.join(current,'package.json'))&&fs.existsSync(path.join(current,'shared','src','index.ts'))&&fs.existsSync(path.join(current,'client','src','GameScene.ts'))&&fs.existsSync(path.join(current,'server','src','rooms','Drop8Room.ts')))return current;
    const parent=path.dirname(current);if(parent===current)break;current=parent;
  }
  throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 프로젝트 최상위 폴더에서 실행하세요.');
}
function currentHash(file:string){return fs.existsSync(file)?hash(fs.readFileSync(file)):'';}
function writeAtomic(file:string,data:Buffer){fs.mkdirSync(path.dirname(file),{recursive:true});const tmp=`${file}.013h-v3.tmp-${process.pid}`;fs.writeFileSync(tmp,data);fs.renameSync(tmp,file);}
function printable(command:string,args:string[]){return [command,...args].map((part)=>/\s|["&|<>^]/.test(part)?`"${part.replaceAll('"','\"')}"`:part).join(' ');}
function run(root:string,command:string,args:string[],required=true){
  console.log(`[${PATCH}] ${printable(command,args)}`);
  const result=process.platform==='win32'
    ?spawnSync('cmd.exe',['/d','/s','/c',printable(command,args)],{cwd:root,stdio:'inherit',windowsHide:true})
    :spawnSync(command,args,{cwd:root,stdio:'inherit'});
  if(result.error){if(required)throw result.error;return false;}
  if(result.status!==0){if(required)throw new Error(`${command} ${args.join(' ')} 실패 (exit=${result.status})`);return false;}
  return true;
}
function repeatVitest(root:string,label:string,testName:string,count:number){
  for(let index=1;index<=count;index++){
    console.log(`[${PATCH}] ${label} 반복 ${index}/${count}`);
    run(root,'pnpm',['--filter','@drop8/server','exec','vitest','run','tests/room.test.ts','-t',testName,'--pool=threads','--maxWorkers=1','--no-file-parallelism','--testTimeout=20000','--hookTimeout=20000','--reporter=dot']);
  }
}
function validateSemantic(root:string){
  const read=(rel:string)=>fs.readFileSync(path.join(root,rel),'utf8');
  const game=read('client/src/GameScene.ts');
  const server=read('server/src/rooms/Drop8Room.ts');
  const shared=read('shared/src/index.ts');
  const water=read('shared/src/maps/water.ts');
  const roomTest=read('server/tests/room.test.ts');
  const mapTest=read('shared/tests/refactor013h-terrain-zone-loot.test.ts');
  for(const marker of ['DROP8_REFACTOR_013H_FIXED_V3_VISIBILITY_ROOF_RIVER_ZONE_SNIPER_AI','Duplicate roof for building','angleAwarePortalPolygon','cutRectFromVisionOverlay','crossSpaceOpening'])if(!game.includes(marker))throw new Error(`시야/지붕 의미 검증 실패: ${marker}`);
  if((game.match(/buildingRoofs\.set\(zone\.id,roof\)/g)||[]).length!==1)throw new Error('Building roof 등록 경로가 정확히 하나가 아닙니다.');
  if(/buildingRoofs\.set\([^)]*room/i.test(game))throw new Error('RoomZone이 roof key로 사용되고 있습니다.');
  for(const marker of ["zoneState='FREE'",'prepareInitialZone','terrainKindAt',"periodicDue&&intent.stuckFor>.35","lastRepathReason='route-healthy'",'preserve-valid-route'])if(!server.includes(marker))throw new Error(`서버 의미 검증 실패: ${marker}`);
  for(const marker of ['zoneFreeSeconds:50','zoneFreeSeconds:65','zoneFreeSeconds:85','createInitialZone','createNextZone','return 1.42','return 1.36'])if(!shared.includes(marker))throw new Error(`공용 규칙 의미 검증 실패: ${marker}`);
  for(const marker of ['terrainAt','riverLandSideAt',"return'deep-water'"])if(!water.includes(marker))throw new Error(`지형 의미 검증 실패: ${marker}`);
  for(const marker of ['waitForCondition','AI door route diagnostic','keeps a healthy AI route until measured stalling triggers replanning','loot.roomIndex = lootSpace.roomIndex'])if(!roomTest.includes(marker))throw new Error(`AI 테스트 의미 검증 실패: ${marker}`);
  for(const marker of ['Object.values(MAP_CONFIGS)','seed<=1000','containment seed'])if(!mapTest.includes(marker))throw new Error(`통계 테스트 의미 검증 실패: ${marker}`);
}
function externalValidation(root:string){
  if(SKIP){console.log(`[${PATCH}] DROP8_PATCH_SKIP_EXTERNAL_VALIDATION=1: 개발용 외부 검증 생략`);return;}
  run(root,'pnpm',['run','typecheck']);
  run(root,'pnpm',['run','lint']);
  run(root,'pnpm',['--filter','@drop8/shared','build']);
  run(root,'pnpm',['--filter','@drop8/shared','test']);
  repeatVitest(root,'AI 문 경로','routes AI around building walls, through the door, and out of collision',20);
  repeatVitest(root,'AI 창문 경로','builds a window route and lets AI complete a server-authoritative vault',20);
  repeatVitest(root,'AI 경로 건강/스턱','keeps a healthy AI route until measured stalling triggers replanning',20);
  for(let index=1;index<=5;index++){console.log(`[${PATCH}] 서버 전체 테스트 ${index}/5`);run(root,'pnpm',['--filter','@drop8/server','test']);}
  run(root,'pnpm',['run','build']);
  if(run(root,'git',['rev-parse','--is-inside-work-tree'],false))run(root,'git',['diff','--check']);
}
function main(){
  const root=findRoot();
  console.log(`[${PATCH}] 프로젝트 루트: ${root}`);
  const states=FILES.map((record)=>{
    const file=path.join(root,record.path),got=currentHash(file);
    if(got===record.after)return'after';
    if(record.kind==='modify'&&got===record.before)return'before';
    if(record.kind==='create'&&!got)return'before';
    throw new Error(`기준 검증 실패: ${record.path}
예상 013G=${record.before||'(없음)'}
예상 013H v3=${record.after}
현재=${got||'(없음)'}`);
  });
  if(states.every((state)=>state==='after')){console.log(`[${PATCH}] 이미 완전히 적용되어 있습니다.`);return;}
  if(states.some((state)=>state==='after'))throw new Error('부분 적용 상태가 감지되었습니다. 자동 덮어쓰기를 중단합니다.');
  console.log(`[${PATCH}] 기준 검증 성공: Refactor 013G, 수정 ${FILES.filter((f)=>f.kind==='modify').length}개, 생성 ${FILES.filter((f)=>f.kind==='create').length}개`);
  console.log(`[${PATCH}] AI: 건강한 경로 보존, 실제 고착/목표 변경 때만 재탐색`);
  console.log(`[${PATCH}] 시야: Building roof / Room occlusion / Portal vision / Entity visibility 분리`);
  console.log(`[${PATCH}] 물: Building·Room 육지 우선, 깊은 강 연속 수영, 서버·클라이언트 공용 terrainAt`);
  console.log(`[${PATCH}] 자기장: FREE 50/65/85초 → 15초 예고 → 분산 첫 원`);
  console.log(`[${PATCH}] 전리품: 작은 맵 유지, 큰 맵·Dock 8 장거리 가중치 보정, Dock 8 216/124/오토바이 8 유지`);
  console.log(`[${PATCH}] 검증: AI 각 20회, 서버 전체 5회, typecheck/lint/shared test/build/git diff`);
  if(DRY){console.log(`[${PATCH}] dry-run 성공. 파일과 백업을 생성하지 않았습니다.`);return;}
  const backup=path.join(root,BACKUP_DIR);
  const stage=path.join(root,`patch_backups/.tmp_refactor_013H_fixed_v3_${process.pid}`);
  const originals=new Map<string,Buffer|undefined>();
  fs.mkdirSync(backup,{recursive:true});fs.mkdirSync(stage,{recursive:true});
  try{
    for(const record of FILES){
      const file=path.join(root,record.path);originals.set(record.path,fs.existsSync(file)?fs.readFileSync(file):undefined);
      const data=decode(record.data);if(hash(data)!==record.after)throw new Error(`내장 payload 해시 불일치: ${record.path}`);
      writeAtomic(path.join(stage,record.path),data);
      if(record.kind==='modify')writeAtomic(path.join(backup,'preimage',record.path),fs.readFileSync(file));
    }
    validateSemantic(stage);
    fs.writeFileSync(path.join(backup,'manifest.json'),JSON.stringify({patch:'013H_FIXED_v3',createdAt:new Date().toISOString(),files:FILES.map((f)=>({path:f.path,kind:f.kind,before:f.before,after:f.after}))},null,2));
    for(const record of FILES)writeAtomic(path.join(root,record.path),fs.readFileSync(path.join(stage,record.path)));
    validateSemantic(root);
    externalValidation(root);
    for(const record of FILES){const got=currentHash(path.join(root,record.path));if(got!==record.after)throw new Error(`적용 후 해시 불일치: ${record.path}`);}
    console.log(`[${PATCH}] 적용과 모든 실행 가능한 검증이 성공했습니다.`);
    console.log(`[${PATCH}] 백업: ${backup}`);
  }catch(error){
    console.error(`[${PATCH}] 실패. 변경 파일을 013G 상태로 자동 롤백합니다.`);
    for(const record of [...FILES].reverse()){const file=path.join(root,record.path),original=originals.get(record.path);if(original===undefined){if(fs.existsSync(file))fs.rmSync(file,{force:true});}else writeAtomic(file,original);}
    throw error;
  }finally{fs.rmSync(stage,{recursive:true,force:true});}
}
try{main();}catch(error){console.error(`[${PATCH}] 오류: ${error instanceof Error?error.message:String(error)}`);process.exitCode=1;}
